use std::collections::HashMap;
use std::path::PathBuf;

pub struct Config {
    pub dir: PathBuf,
    pub width: u16,
    pub height: u16,
    pub key: String,
    pub editor: String,
}

impl Config {
    pub fn from_env() -> Self {
        let dir = std::env::var("TNOTE_DIR")
            .map(PathBuf::from)
            .unwrap_or_else(|_| {
                let home = PathBuf::from(
                    std::env::var("HOME").unwrap_or_else(|_| ".".to_string()),
                );
                let target    = home.join(".tnote");
                let from_old  = home.join(".tnotes");
                let from_old2 = home.join(".termnotes");

                if !target.exists() {
                    if from_old.exists() {
                        if let Err(e) = std::fs::rename(&from_old, &target) {
                            eprintln!("tnote: could not migrate {} → {}: {}", from_old.display(), target.display(), e);
                        } else {
                            eprintln!("tnote: migrated {} → {}", from_old.display(), target.display());
                        }
                    } else if from_old2.exists() {
                        if let Err(e) = std::fs::rename(&from_old2, &target) {
                            eprintln!("tnote: could not migrate {} → {}: {}", from_old2.display(), target.display(), e);
                        } else {
                            eprintln!("tnote: migrated {} → {}", from_old2.display(), target.display());
                        }
                    }
                }
                target
            });

        let file = read_config_file(&dir.join("meta").join("config"));

        Config {
            width:  parse_u16("TNOTE_WIDTH",  file.get("width").map(String::as_str),  62),
            height: parse_u16("TNOTE_HEIGHT", file.get("height").map(String::as_str), 22),
            key:    parse_str("TNOTE_KEY",    file.get("key").map(String::as_str),    "t"),
            editor: parse_str("EDITOR",       file.get("editor").map(String::as_str), "vim"),
            dir,
        }
    }

    pub fn save(&self) -> std::io::Result<()> {
        std::fs::create_dir_all(self.dir.join("meta"))?;
        std::fs::write(
            self.dir.join("meta").join("config"),
            format!(
                "editor={}\nkey={}\nwidth={}\nheight={}\n",
                self.editor, self.key, self.width, self.height
            ),
        )
    }
}

pub fn read_config_file(path: &std::path::Path) -> HashMap<String, String> {
    let mut map = HashMap::new();
    if let Ok(content) = std::fs::read_to_string(path) {
        for line in content.lines() {
            if let Some((k, v)) = line.split_once('=') {
                map.insert(k.trim().to_string(), v.trim().to_string());
            }
        }
    }
    map
}

pub fn parse_u16(env_key: &str, file_val: Option<&str>, default: u16) -> u16 {
    std::env::var(env_key).ok().and_then(|v| v.parse().ok())
        .or_else(|| file_val.and_then(|v| v.parse().ok()))
        .unwrap_or(default)
}

pub fn parse_str(env_key: &str, file_val: Option<&str>, default: &str) -> String {
    std::env::var(env_key).ok()
        .or_else(|| file_val.map(str::to_string))
        .unwrap_or_else(|| default.to_string())
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::path::Path;

    // Env key that is very unlikely to be set in any real environment.
    const ABSENT: &str = "TNOTE_TEST_ABSENT_KEY_XYZ_99999";

    // ── read_config_file ──────────────────────────────────────────────────────

    #[test]
    fn read_config_file_returns_empty_for_missing_file() {
        let map = read_config_file(Path::new("/nonexistent/path/config"));
        assert!(map.is_empty());
    }

    #[test]
    fn read_config_file_parses_key_value_pairs() {
        let tmp = tempfile::tempdir().unwrap();
        let path = tmp.path().join("config");
        std::fs::write(&path, "editor=nvim\nwidth=80\n").unwrap();
        let map = read_config_file(&path);
        assert_eq!(map.get("editor").map(String::as_str), Some("nvim"));
        assert_eq!(map.get("width").map(String::as_str), Some("80"));
    }

    #[test]
    fn read_config_file_trims_whitespace() {
        let tmp = tempfile::tempdir().unwrap();
        let path = tmp.path().join("config");
        std::fs::write(&path, "  key  =  t  \n").unwrap();
        let map = read_config_file(&path);
        assert_eq!(map.get("key").map(String::as_str), Some("t"));
    }

    #[test]
    fn read_config_file_ignores_lines_without_equals() {
        let tmp = tempfile::tempdir().unwrap();
        let path = tmp.path().join("config");
        std::fs::write(&path, "# comment\neditor=vim\n").unwrap();
        let map = read_config_file(&path);
        assert!(!map.contains_key("# comment"));
        assert_eq!(map.get("editor").map(String::as_str), Some("vim"));
    }

    // ── parse_u16 ─────────────────────────────────────────────────────────────

    #[test]
    fn parse_u16_uses_file_val_when_env_absent() {
        assert_eq!(parse_u16(ABSENT, Some("42"), 0), 42);
    }

    #[test]
    fn parse_u16_uses_default_when_both_absent() {
        assert_eq!(parse_u16(ABSENT, None, 99), 99);
    }

    #[test]
    fn parse_u16_falls_back_to_default_on_invalid_file_val() {
        assert_eq!(parse_u16(ABSENT, Some("bad"), 7), 7);
    }

    #[test]
    fn parse_u16_falls_back_to_default_on_overflow_file_val() {
        assert_eq!(parse_u16(ABSENT, Some("99999"), 7), 7);
    }

    // ── parse_str ─────────────────────────────────────────────────────────────

    #[test]
    fn parse_str_uses_file_val_when_env_absent() {
        assert_eq!(parse_str(ABSENT, Some("nvim"), "vim"), "nvim");
    }

    #[test]
    fn parse_str_uses_default_when_both_absent() {
        assert_eq!(parse_str(ABSENT, None, "vim"), "vim");
    }

    // ── Config::save ─────────────────────────────────────────────────────────

    #[test]
    fn config_save_writes_all_fields() {
        let tmp = tempfile::tempdir().unwrap();
        let cfg = Config {
            dir:    tmp.path().to_path_buf(),
            editor: "nano".to_string(),
            key:    "n".to_string(),
            width:  100,
            height: 30,
        };
        cfg.save().unwrap();
        let content = std::fs::read_to_string(tmp.path().join("meta/config")).unwrap();
        assert!(content.contains("editor=nano"));
        assert!(content.contains("key=n"));
        assert!(content.contains("width=100"));
        assert!(content.contains("height=30"));
    }

    #[test]
    fn config_save_round_trips_via_read_config_file() {
        let tmp = tempfile::tempdir().unwrap();
        let cfg = Config {
            dir:    tmp.path().to_path_buf(),
            editor: "hx".to_string(),
            key:    "g".to_string(),
            width:  70,
            height: 25,
        };
        cfg.save().unwrap();
        let map = read_config_file(&tmp.path().join("meta/config"));
        assert_eq!(map.get("editor").map(String::as_str), Some("hx"));
        assert_eq!(map.get("key").map(String::as_str), Some("g"));
        assert_eq!(map.get("width").map(String::as_str), Some("70"));
        assert_eq!(map.get("height").map(String::as_str), Some("25"));
    }
}

use std::io::{self, Read, Write};
use std::path::Path;
use std::sync::mpsc;
use std::thread;
use std::time::Duration;

use portable_pty::{CommandBuilder, PtySize};
use ratatui::backend::CrosstermBackend;
use ratatui::crossterm::cursor;
use ratatui::crossterm::event::{self, Event, KeyCode, KeyEvent, KeyModifiers};
use ratatui::crossterm::execute;
use ratatui::crossterm::terminal::{
    self, disable_raw_mode, enable_raw_mode, EnterAlternateScreen, LeaveAlternateScreen,
};
use ratatui::layout::Rect;
use ratatui::style::{Color, Modifier, Style};
use ratatui::text::Line;
use ratatui::widgets::{Block, Borders};
use ratatui::{Terminal, TerminalOptions, Viewport};

fn make_rect(width: u16, height: u16) -> io::Result<(Rect, u16, u16)> {
    let (term_w, term_h) = terminal::size()?;
    let popup_w = width.min(term_w);
    let popup_h = height.min(term_h);
    let rect = Rect::new(term_w.saturating_sub(popup_w), 0, popup_w, popup_h);
    let inner_w = popup_w.saturating_sub(2);
    let inner_h = popup_h.saturating_sub(2);
    Ok((rect, inner_w, inner_h))
}

pub fn run(file: &Path, label: &str, width: u16, height: u16) -> io::Result<()> {
    // Initial sizing for the PTY (pre-alternate-screen).
    let (_, init_iw, init_ih) = make_rect(width, height)?;

    let background = capture_pane_snapshot();

    // ── PTY ────────────────────────────────────────────────────────────────────

    let pty_system = portable_pty::native_pty_system();
    let pair = pty_system
        .openpty(PtySize { rows: init_ih, cols: init_iw, pixel_width: 0, pixel_height: 0 })
        .map_err(|e| io::Error::new(io::ErrorKind::Other, e.to_string()))?;

    let editor = std::env::var("EDITOR").unwrap_or_else(|_| "vim".to_string());
    let mut cmd = CommandBuilder::new(&editor);
    cmd.arg(file);
    let mut child = pair.slave
        .spawn_command(cmd)
        .map_err(|e| io::Error::new(io::ErrorKind::Other, e.to_string()))?;
    drop(pair.slave);

    let mut pty_writer = pair.master
        .take_writer()
        .map_err(|e| io::Error::new(io::ErrorKind::Other, e.to_string()))?;
    let mut pty_reader = pair.master
        .try_clone_reader()
        .map_err(|e| io::Error::new(io::ErrorKind::Other, e.to_string()))?;

    // Read PTY output on a background thread; send bytes to main thread.
    let (tx, rx) = mpsc::channel::<Vec<u8>>();
    thread::spawn(move || {
        let mut buf = [0u8; 4096];
        loop {
            match pty_reader.read(&mut buf) {
                Ok(0) | Err(_) => break,
                Ok(n) => {
                    if tx.send(buf[..n].to_vec()).is_err() {
                        break;
                    }
                }
            }
        }
    });

    let mut parser = vt100::Parser::new(init_ih, init_iw, 0);

    // ── Terminal setup ─────────────────────────────────────────────────────────

    let default_hook = std::panic::take_hook();
    std::panic::set_hook(Box::new(move |info| {
        let _ = disable_raw_mode();
        let _ = execute!(io::stdout(), LeaveAlternateScreen, cursor::Show);
        default_hook(info);
    }));

    enable_raw_mode()?;
    execute!(io::stdout(), EnterAlternateScreen)?;

    // Re-query size after entering alternate screen — some terminals (e.g. iTerm
    // fullscreen) report a different size at this point.
    let (mut rect, mut inner_w, mut inner_h) = make_rect(width, height)?;

    if let Some(bg) = background {
        paint_background(&bg)?;
    }

    // Pre-clear the popup rect.
    execute!(io::stdout(), ratatui::crossterm::style::ResetColor)?;
    let blank = " ".repeat(rect.width as usize);
    for row in rect.y..rect.y + rect.height {
        execute!(io::stdout(), cursor::MoveTo(rect.x, row))?;
        write!(io::stdout(), "{}", blank)?;
    }
    io::stdout().flush()?;

    let mut terminal = Terminal::with_options(
        CrosstermBackend::new(io::stdout()),
        TerminalOptions { viewport: Viewport::Fixed(rect) },
    )?;

    // ── Event loop ─────────────────────────────────────────────────────────────

    'main: loop {
        // Drain all pending PTY output; exit if the child process closed the PTY.
        loop {
            match rx.try_recv() {
                Ok(data) => parser.process(&data),
                Err(mpsc::TryRecvError::Empty) => break,
                Err(mpsc::TryRecvError::Disconnected) => break 'main,
            }
        }

        terminal.draw(|frame| {
            // Border
            let block = Block::default()
                .borders(Borders::ALL)
                .title_top(Line::from(format!(" tnote: {} ", label)));
            frame.render_widget(block, rect);

            // PTY screen cells
            let screen = parser.screen();
            {
                let buf = frame.buffer_mut();
                for row in 0..inner_h {
                    for col in 0..inner_w {
                        if let Some(cell) = screen.cell(row, col) {
                            let s = cell.contents();
                            let s = if s.is_empty() { " ".to_string() } else { s };
                            buf.set_string(
                                rect.x + 1 + col,
                                rect.y + 1 + row,
                                s,
                                cell_style(cell),
                            );
                        }
                    }
                }
            }

            // Cursor
            if !screen.hide_cursor() {
                let (cur_row, cur_col) = screen.cursor_position();
                if cur_row < inner_h && cur_col < inner_w {
                    frame.set_cursor_position((
                        rect.x + 1 + cur_col,
                        rect.y + 1 + cur_row,
                    ));
                }
            }
        })?;

        // Forward keyboard input to the PTY.
        if event::poll(Duration::from_millis(16))? {
            match event::read()? {
                Event::Key(key) => {
                    let bytes = key_to_bytes(key);
                    if !bytes.is_empty() {
                        let _ = pty_writer.write_all(&bytes);
                        let _ = pty_writer.flush();
                    }
                }
                Event::Resize(_, _) => {
                    if let Ok((new_rect, new_iw, new_ih)) = make_rect(width, height) {
                        rect = new_rect;
                        inner_w = new_iw;
                        inner_h = new_ih;
                        parser.set_size(inner_h, inner_w);
                        terminal.resize(rect)?;
                    }
                }
                _ => {}
            }
        }
    }

    let _ = child.wait();
    execute!(io::stdout(), LeaveAlternateScreen, cursor::Show)?;
    disable_raw_mode()?;
    Ok(())
}

// ── Helpers ───────────────────────────────────────────────────────────────────

fn cell_style(cell: &vt100::Cell) -> Style {
    let fg = vt100_color(cell.fgcolor());
    let bg = vt100_color(cell.bgcolor());
    let mut style = Style::default().fg(fg).bg(bg);
    if cell.bold()      { style = style.add_modifier(Modifier::BOLD); }
    if cell.italic()    { style = style.add_modifier(Modifier::ITALIC); }
    if cell.underline() { style = style.add_modifier(Modifier::UNDERLINED); }
    if cell.inverse()   { style = style.add_modifier(Modifier::REVERSED); }
    style
}

pub fn vt100_color(color: vt100::Color) -> Color {
    match color {
        vt100::Color::Default      => Color::Reset,
        vt100::Color::Idx(n)       => Color::Indexed(n),
        vt100::Color::Rgb(r, g, b) => Color::Rgb(r, g, b),
    }
}

/// Convert a crossterm key event into the byte sequence a terminal would send.
pub fn key_to_bytes(key: KeyEvent) -> Vec<u8> {
    let ctrl = key.modifiers.contains(KeyModifiers::CONTROL);
    let alt  = key.modifiers.contains(KeyModifiers::ALT);

    let mut bytes: Vec<u8> = match key.code {
        KeyCode::Char(c) if ctrl => {
            let c = c.to_ascii_lowercase();
            if ('a'..='z').contains(&c) { vec![c as u8 - b'a' + 1] }
            else if c == ' '            { vec![0] }
            else                        { vec![] }
        }
        KeyCode::Char(c) => {
            let mut buf = [0u8; 4];
            c.encode_utf8(&mut buf).as_bytes().to_vec()
        }
        KeyCode::Enter     => vec![b'\r'],
        KeyCode::Backspace => vec![0x7f],
        KeyCode::Delete    => vec![0x1b, b'[', b'3', b'~'],
        KeyCode::Esc       => vec![0x1b],
        KeyCode::Tab       => vec![b'\t'],
        KeyCode::BackTab   => vec![0x1b, b'[', b'Z'],
        KeyCode::Up        => vec![0x1b, b'[', b'A'],
        KeyCode::Down      => vec![0x1b, b'[', b'B'],
        KeyCode::Right     => vec![0x1b, b'[', b'C'],
        KeyCode::Left      => vec![0x1b, b'[', b'D'],
        KeyCode::Home      => vec![0x1b, b'[', b'H'],
        KeyCode::End       => vec![0x1b, b'[', b'F'],
        KeyCode::PageUp    => vec![0x1b, b'[', b'5', b'~'],
        KeyCode::PageDown  => vec![0x1b, b'[', b'6', b'~'],
        KeyCode::F(1)  => vec![0x1b, b'O', b'P'],
        KeyCode::F(2)  => vec![0x1b, b'O', b'Q'],
        KeyCode::F(3)  => vec![0x1b, b'O', b'R'],
        KeyCode::F(4)  => vec![0x1b, b'O', b'S'],
        KeyCode::F(5)  => vec![0x1b, b'[', b'1', b'5', b'~'],
        KeyCode::F(6)  => vec![0x1b, b'[', b'1', b'7', b'~'],
        KeyCode::F(7)  => vec![0x1b, b'[', b'1', b'8', b'~'],
        KeyCode::F(8)  => vec![0x1b, b'[', b'1', b'9', b'~'],
        KeyCode::F(9)  => vec![0x1b, b'[', b'2', b'0', b'~'],
        KeyCode::F(10) => vec![0x1b, b'[', b'2', b'1', b'~'],
        KeyCode::F(11) => vec![0x1b, b'[', b'2', b'3', b'~'],
        KeyCode::F(12) => vec![0x1b, b'[', b'2', b'4', b'~'],
        _ => vec![],
    };

    if alt && !bytes.is_empty() && key.code != KeyCode::Esc {
        bytes.insert(0, 0x1b);
    }

    bytes
}

/// Paint captured tmux pane content as the background of the alternate screen.
fn paint_background(bg: &[u8]) -> io::Result<()> {
    let content = String::from_utf8_lossy(bg);
    let lines: Vec<&str> = content.split('\n').collect();
    let count = if lines.last().map(|l| l.is_empty()).unwrap_or(false) {
        lines.len() - 1
    } else {
        lines.len()
    };
    for row in 0..count {
        execute!(io::stdout(), cursor::MoveTo(0, row as u16))?;
        write!(io::stdout(), "{}", lines[row])?;
    }
    io::stdout().flush()
}

/// Capture the current tmux pane's visible content with ANSI escape sequences.
fn capture_pane_snapshot() -> Option<Vec<u8>> {
    if std::env::var("TMUX").is_err() {
        return None;
    }
    let out = std::process::Command::new("tmux")
        .args(["capture-pane", "-p", "-e"])
        .output()
        .ok()?;
    if out.status.success() && !out.stdout.is_empty() {
        Some(out.stdout)
    } else {
        None
    }
}

use crate::config::Config;
use std::fs;
use std::io::Write;
use std::path::{Path, PathBuf};
use std::process::Command;

pub fn which(cmd: &str) -> bool {
    std::process::Command::new("sh")
        .args(["-c", &format!("command -v {} >/dev/null 2>&1", cmd)])
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::null())
        .status()
        .map(|s| s.success())
        .unwrap_or(false)
}

fn user_tmux_conf() -> Option<PathBuf> {
    std::env::var("HOME").ok().map(|h| PathBuf::from(h).join(".tmux.conf"))
}

fn home_dir() -> Option<PathBuf> {
    std::env::var("HOME").ok().map(PathBuf::from)
}

/// Detect the user's shell from $SHELL.
fn detect_shell() -> Option<String> {
    std::env::var("SHELL").ok().and_then(|s| {
        s.rsplit('/').next().map(|n| n.to_string())
    })
}

/// Return the rc file path for the given shell.
fn shell_rc(shell: &str) -> Option<PathBuf> {
    let home = home_dir()?;
    match shell {
        "zsh"  => Some(home.join(".zshrc")),
        "bash" => {
            // Keybindings belong in .bashrc (interactive shells), not .bash_profile (login shells).
            Some(home.join(".bashrc"))
        }
        "fish" => {
            let dir = home.join(".config/fish");
            let _ = std::fs::create_dir_all(&dir);
            Some(dir.join("config.fish"))
        }
        _ => None,
    }
}

/// Generate the shell keybinding snippet for the given shell and key.
fn shell_binding(shell: &str, key: &str) -> Option<String> {
    let ctrl_key = format!("\\C-{}", key);
    match shell {
        "zsh" => Some(format!(
            "# tnote keybinding — managed by 'tnote setup' / 'tnote uninstall'\n\
             if [ -z \"$TMUX\" ]; then bindkey -s '{}' 'tnote\\n'; fi",
            ctrl_key
        )),
        "bash" => Some(format!(
            "# tnote keybinding — managed by 'tnote setup' / 'tnote uninstall'\n\
             if [ -z \"$TMUX\" ]; then bind '\"{}\":\"tnote\\n\"'; fi",
            ctrl_key
        )),
        "fish" => Some(format!(
            "# tnote keybinding — managed by 'tnote setup' / 'tnote uninstall'\n\
             if not set -q TMUX; bind \\c{} 'tnote; commandline -f repaint'; end",
            key
        )),
        _ => None,
    }
}

/// Marker line used to identify the tnote block in shell rc files.
const SHELL_MARKER: &str = "# tnote keybinding — managed by 'tnote setup' / 'tnote uninstall'";

fn add_shell_binding(rc_path: &Path, binding: &str) -> std::io::Result<()> {
    let content = fs::read_to_string(rc_path).unwrap_or_default();
    // Remove any existing tnote block first
    let cleaned = remove_shell_block(&content);
    let mut f = fs::OpenOptions::new().create(true).write(true).truncate(true).open(rc_path)?;
    f.write_all(cleaned.as_bytes())?;
    if !cleaned.is_empty() && !cleaned.ends_with('\n') {
        writeln!(f)?;
    }
    writeln!(f, "{}", binding)?;
    Ok(())
}

fn remove_shell_binding(rc_path: &Path) -> std::io::Result<bool> {
    let Ok(content) = fs::read_to_string(rc_path) else { return Ok(false); };
    let cleaned = remove_shell_block(&content);
    if cleaned == content {
        return Ok(false);
    }
    fs::write(rc_path, &cleaned)?;
    Ok(true)
}

/// Remove the tnote marker line and the line immediately following it.
fn remove_shell_block(content: &str) -> String {
    let lines: Vec<&str> = content.lines().collect();
    let mut result = Vec::new();
    let mut skip_next = false;
    for line in &lines {
        if skip_next {
            skip_next = false;
            continue;
        }
        if line.trim() == SHELL_MARKER {
            skip_next = true;
            continue;
        }
        result.push(*line);
    }
    let mut out = result.join("\n");
    if content.ends_with('\n') && !out.is_empty() {
        out.push('\n');
    }
    out
}

pub fn add_source_line(user_conf: &Path, source_path: &Path) -> std::io::Result<()> {
    let line = format!("source-file {}", source_path.display());
    let content = fs::read_to_string(user_conf).unwrap_or_default();
    if content.lines().any(|l| l.trim() == line) {
        return Ok(());
    }
    let mut f = fs::OpenOptions::new().create(true).append(true).open(user_conf)?;
    if !content.is_empty() && !content.ends_with('\n') {
        writeln!(f)?;
    }
    writeln!(f, "{}", line)?;
    Ok(())
}

pub fn remove_source_line(user_conf: &Path, source_path: &Path) -> std::io::Result<()> {
    let Ok(content) = fs::read_to_string(user_conf) else { return Ok(()); };
    let line = format!("source-file {}", source_path.display());
    let filtered: Vec<&str> = content.lines().filter(|l| l.trim() != line).collect();
    let new_content = if content.ends_with('\n') {
        format!("{}\n", filtered.join("\n"))
    } else {
        filtered.join("\n")
    };
    if new_content != content {
        fs::write(user_conf, new_content)?;
    }
    Ok(())
}

pub fn run(config: &Config) {
    if let Err(e) = fs::create_dir_all(&config.dir) {
        eprintln!("tnote setup: failed to create {}: {}", config.dir.display(), e);
        std::process::exit(1);
    }

    let meta_dir = config.dir.join("meta");
    if let Err(e) = fs::create_dir_all(&meta_dir) {
        eprintln!("tnote setup: failed to create {}: {}", meta_dir.display(), e);
        std::process::exit(1);
    }

    // ── tmux bindings ─────────────────────────────────────────────────────
    if which("tmux") || user_tmux_conf().map(|p| p.exists()).unwrap_or(false) {
        let tmux_conf_path = meta_dir.join("tmux.conf");

        if let Ok(old) = fs::read_to_string(&tmux_conf_path) {
            if let Some(old_key) = old.lines()
                .find_map(|l| l.strip_prefix("bind-key ").and_then(|r| r.split_whitespace().next()))
            {
                if old_key != config.key {
                    let _ = Command::new("tmux").args(["unbind-key", old_key]).status();
                }
            }
        }

        let key = &config.key;
        let tmux_conf = format!(
            "# tnote key bindings — managed by 'tnote setup' / 'tnote uninstall'\n\
             unbind-key {key}\n\
             bind-key {key} run-shell 'tnote'\n\
             set -s command-alias[100] \"tnote=run-shell 'tnote'\"\n\
             set -s command-alias[101] \"tnote-show=run-shell 'tnote show'\"\n\
             set -s command-alias[102] \"tnote-list=run-shell 'tnote list'\"\n\
             set -s command-alias[103] \"tnote-path=run-shell 'tnote path'\"\n\
             set -s command-alias[104] \"tnote-clean=run-shell 'tnote clean'\"\n\
             set -s command-alias[105] \"tnote-help=run-shell 'tnote help'\"\n\
             set -s command-alias[106] \"tnote-name=run-shell 'tnote name'\"\n",
            key = key,
        );

        if let Err(e) = fs::write(&tmux_conf_path, &tmux_conf) {
            eprintln!("tnote setup: failed to write {}: {}", tmux_conf_path.display(), e);
            std::process::exit(1);
        }
        println!("tnote setup: wrote {}", tmux_conf_path.display());

        let status = Command::new("tmux")
            .args(["source-file", &tmux_conf_path.to_string_lossy()])
            .status();

        match status {
            Ok(s) if s.success() => println!("tnote setup: sourced bindings into live tmux session"),
            _ => eprintln!("tnote setup: tmux source-file failed"),
        }

        if let Some(user_conf) = user_tmux_conf() {
            match add_source_line(&user_conf, &tmux_conf_path) {
                Ok(_) => println!("tnote setup: added source-file line to {}", user_conf.display()),
                Err(e) => eprintln!("tnote setup: could not update {}: {}", user_conf.display(), e),
            }
        }

        println!("tnote setup: tmux binding: prefix+{} opens/closes tnote popup", config.key);
    }

    // ── shell keybinding ──────────────────────────────────────────────────
    if let Some(shell) = detect_shell() {
        if let (Some(rc), Some(binding)) = (shell_rc(&shell), shell_binding(&shell, &config.key)) {
            match add_shell_binding(&rc, &binding) {
                Ok(_) => {
                    println!("tnote setup: added Ctrl-{} binding to {}", config.key, rc.display());
                    println!("tnote setup: restart your shell or run: source {}", rc.display());
                }
                Err(e) => eprintln!("tnote setup: could not update {}: {}", rc.display(), e),
            }
        } else {
            println!("tnote setup: unsupported shell '{}', skipping shell keybinding", shell);
        }
    }

    println!("tnote setup: setup complete.");
}

pub fn uninstall(config: &Config) {
    let tmux_conf_path = config.dir.join("meta").join("tmux.conf");
    let key = &config.key;

    // ── tmux ──────────────────────────────────────────────────────────────
    let cleared = format!(
        "# tnote key bindings — cleared by 'tnote uninstall'\n\
         unbind-key {key}\n\
         set -su command-alias[100]\n\
         set -su command-alias[101]\n\
         set -su command-alias[102]\n\
         set -su command-alias[103]\n\
         set -su command-alias[104]\n\
         set -su command-alias[105]\n\
         set -su command-alias[106]\n",
        key = key
    );

    match fs::write(&tmux_conf_path, &cleared) {
        Ok(_) => {
            let _ = Command::new("tmux")
                .args(["source-file", &tmux_conf_path.to_string_lossy()])
                .status();
            println!("tnote uninstall: cleared tmux bindings");
        }
        Err(_) => {
            let _ = Command::new("tmux").args(["unbind-key", key]).status();
        }
    }

    if let Some(user_conf) = user_tmux_conf() {
        match remove_source_line(&user_conf, &tmux_conf_path) {
            Ok(_) => println!("tnote uninstall: removed source-file line from {}", user_conf.display()),
            Err(e) => eprintln!("tnote uninstall: could not update {}: {}", user_conf.display(), e),
        }
    }

    // ── shell keybinding ──────────────────────────────────────────────────
    if let Some(shell) = detect_shell() {
        if let Some(rc) = shell_rc(&shell) {
            match remove_shell_binding(&rc) {
                Ok(true) => println!("tnote uninstall: removed keybinding from {}", rc.display()),
                Ok(false) => {}
                Err(e) => eprintln!("tnote uninstall: could not update {}: {}", rc.display(), e),
            }
        }
    }

    println!("tnote uninstall: complete.");
}

#[cfg(test)]
mod tests {
    use super::*;

    // ── add_source_line ───────────────────────────────────────────────────────

    #[test]
    fn add_source_line_creates_file_if_absent() {
        let tmp = tempfile::tempdir().unwrap();
        let conf = tmp.path().join(".tmux.conf");
        let src  = tmp.path().join("meta/tmux.conf");
        add_source_line(&conf, &src).unwrap();
        let content = fs::read_to_string(&conf).unwrap();
        assert!(content.contains(&format!("source-file {}", src.display())));
    }

    #[test]
    fn add_source_line_appends_to_existing_content() {
        let tmp = tempfile::tempdir().unwrap();
        let conf = tmp.path().join(".tmux.conf");
        let src  = tmp.path().join("meta/tmux.conf");
        fs::write(&conf, "set -g mouse on\n").unwrap();
        add_source_line(&conf, &src).unwrap();
        let content = fs::read_to_string(&conf).unwrap();
        assert!(content.starts_with("set -g mouse on\n"));
        assert!(content.contains(&format!("source-file {}", src.display())));
    }

    #[test]
    fn add_source_line_is_idempotent() {
        let tmp = tempfile::tempdir().unwrap();
        let conf = tmp.path().join(".tmux.conf");
        let src  = tmp.path().join("meta/tmux.conf");
        add_source_line(&conf, &src).unwrap();
        add_source_line(&conf, &src).unwrap();
        let content = fs::read_to_string(&conf).unwrap();
        let count = content.lines()
            .filter(|l| l.trim() == format!("source-file {}", src.display()))
            .count();
        assert_eq!(count, 1);
    }

    #[test]
    fn add_source_line_adds_newline_before_if_file_lacks_trailing_newline() {
        let tmp = tempfile::tempdir().unwrap();
        let conf = tmp.path().join(".tmux.conf");
        let src  = tmp.path().join("meta/tmux.conf");
        fs::write(&conf, "set -g mouse on").unwrap(); // no trailing newline
        add_source_line(&conf, &src).unwrap();
        let content = fs::read_to_string(&conf).unwrap();
        // The source line should be on its own line
        assert!(content.contains(&format!("\nsource-file {}", src.display())));
    }

    // ── remove_source_line ────────────────────────────────────────────────────

    #[test]
    fn remove_source_line_removes_the_line() {
        let tmp = tempfile::tempdir().unwrap();
        let conf = tmp.path().join(".tmux.conf");
        let src  = tmp.path().join("meta/tmux.conf");
        fs::write(&conf, format!("set -g mouse on\nsource-file {}\n", src.display())).unwrap();
        remove_source_line(&conf, &src).unwrap();
        let content = fs::read_to_string(&conf).unwrap();
        assert!(!content.contains(&format!("source-file {}", src.display())));
        assert!(content.contains("set -g mouse on"));
    }

    #[test]
    fn remove_source_line_noop_when_line_absent() {
        let tmp = tempfile::tempdir().unwrap();
        let conf = tmp.path().join(".tmux.conf");
        let src  = tmp.path().join("meta/tmux.conf");
        fs::write(&conf, "set -g mouse on\n").unwrap();
        remove_source_line(&conf, &src).unwrap();
        let content = fs::read_to_string(&conf).unwrap();
        assert_eq!(content, "set -g mouse on\n");
    }

    #[test]
    fn remove_source_line_ok_when_file_does_not_exist() {
        let tmp = tempfile::tempdir().unwrap();
        let conf = tmp.path().join(".tmux.conf");
        let src  = tmp.path().join("meta/tmux.conf");
        // conf does not exist — should not error
        remove_source_line(&conf, &src).unwrap();
    }

    #[test]
    fn remove_source_line_preserves_trailing_newline() {
        let tmp = tempfile::tempdir().unwrap();
        let conf = tmp.path().join(".tmux.conf");
        let src  = tmp.path().join("meta/tmux.conf");
        fs::write(&conf, format!("a\nsource-file {}\nb\n", src.display())).unwrap();
        remove_source_line(&conf, &src).unwrap();
        let content = fs::read_to_string(&conf).unwrap();
        assert!(content.ends_with('\n'));
        assert_eq!(content, "a\nb\n");
    }
}

pub mod config;
pub mod editor;
pub mod install;
pub mod notes;
pub mod tmux;

use tnote::{config, editor, install, notes, tmux};

use clap::{CommandFactory, Parser, Subcommand, ValueEnum};
use config::Config;
use std::io::{self, Write};
use notes::Notes;
use owo_colors::{OwoColorize, Style, Stream::Stdout, Stream::Stderr};
use std::fs;
use std::path::PathBuf;

#[derive(ValueEnum, Clone)]
enum ClearScope {
    /// Remove files without a recognized prefix (tmux-, shell-, named-)
    Unprefixed,
    /// Remove all named notes
    Named,
    /// Remove all tmux-keyed notes regardless of window liveness
    Tmux,
    /// Remove all notes
    All,

}

impl From<ClearScope> for notes::ClearScope {
    fn from(s: ClearScope) -> Self {
        match s {
            ClearScope::Unprefixed => notes::ClearScope::Unprefixed,
            ClearScope::Named      => notes::ClearScope::Named,
            ClearScope::Tmux       => notes::ClearScope::Tmux,
            ClearScope::All        => notes::ClearScope::All,
        }
    }
}

#[derive(Parser)]
#[command(name = "tnote", about = "Terminal Notepad", disable_help_subcommand = true, version)]
struct Cli {
    #[command(subcommand)]
    command: Option<Cmd>,
}

#[derive(Subcommand)]
enum Cmd {
    /// Name this window's note (also renames the tmux window)
    Name { name: Option<String> },
    /// Print note contents inline
    Show,
    /// Remove notes not tied to a running process or window
    Clean {
        /// Also remove notes in the given category: unprefixed, named, tmux, all
        #[arg(long, value_name = "CATEGORY")]
        all: Option<ClearScope>,
        /// Remove a specific named note by name
        #[arg(long, value_name = "NAME")]
        named: Option<String>,
        /// Print what would be removed without removing anything
        #[arg(long)]
        dryrun: bool,
    },
    /// List all notes with line counts
    List,
    /// Print the note file path
    Path,
    /// Configure editor, key binding, and dimensions, then install keybindings
    Setup,
    /// Remove tmux and shell keybindings
    Uninstall,
    /// Show usage
    Help,
    /// Generate shell completions
    Completions {
        /// Shell to generate completions for
        #[arg(value_enum)]
        shell: clap_complete::Shell,
    },
    /// Internal: run editor inline when already inside a tmux display-popup
    #[command(hide = true)]
    Popup { window_key: Option<String> },
}

fn main() {
    let cli = Cli::parse();
    let config = Config::from_env();
    let notes = Notes::new(config.dir.clone());

    if let Err(e) = notes.ensure_dir() {
        eprintln!("tnote: failed to create notes dir {}: {}", config.dir.display(), e);
        std::process::exit(1);
    }

    match &cli.command {
        None => cmd_open(&config, &notes),
        Some(Cmd::Name { name }) => cmd_name(&notes, name.as_deref()),
        Some(Cmd::Show) => cmd_show(&notes),
        Some(Cmd::Clean { all, named, dryrun }) => cmd_clean(&notes, all.clone(), named.as_deref(), *dryrun),
        Some(Cmd::List) => cmd_list(&notes),
        Some(Cmd::Path) => cmd_path(&notes),
        Some(Cmd::Setup) => cmd_setup(&config),
        Some(Cmd::Uninstall) => install::uninstall(&config),
        Some(Cmd::Help) => print_help(),
        Some(Cmd::Completions { shell }) => {
            clap_complete::generate(*shell, &mut Cli::command(), "tnote", &mut std::io::stdout());
        }
        Some(Cmd::Popup { window_key }) => {
            let key = window_key.as_deref()
                .filter(|s| !s.is_empty())
                .map(|s| s.to_string())
                .or_else(|| std::env::var("TNOTE_WINDOW_KEY").ok())
                .or_else(|| tmux::window_key())
                .unwrap_or_else(|| notes::shell_session_key());
            cmd_popup_inline(&config, &notes, &key);
        }
    }
}

// ── Helpers ───────────────────────────────────────────────────────────────────

fn current_note(notes: &Notes) -> (String, PathBuf) {
    let key = if tmux::is_in_tmux() {
        tmux::window_key().unwrap_or_else(|| notes::shell_session_key())
    } else {
        notes::shell_session_key()
    };
    let file = notes.file_for_key(&key);
    (key, file)
}

// ── Subcommands ───────────────────────────────────────────────────────────────

fn cmd_open(config: &Config, notes: &Notes) {
    // First-run hint
    if !config.dir.join("meta").join("config").exists() {
        eprintln!("tnote: tip — run 'tnote setup' to configure keybindings and editor");
    }

    if tmux::is_in_tmux() && tmux::is_popup_session() {
        let _ = std::process::Command::new("tmux").args(["detach-client"]).status();
        return;
    }

    let (key, file) = current_note(notes);
    let label = notes.label_for_key(&key);

    if !file.exists() {
        let _ = fs::write(&file, "");
    }

    let result = if tmux::is_in_tmux() {
        tmux::open_popup_session(&file, &key, config)
    } else {
        editor::run(&file, &label, config.width, config.height)
    };

    if let Err(e) = result {
        if e.kind() == std::io::ErrorKind::NotFound {
            eprintln!("tnote: editor '{}' not found — run 'tnote setup' to configure", config.editor);
        } else {
            eprintln!("tnote: {}", e);
        }
        std::process::exit(1);
    }
}

fn cmd_popup_inline(_config: &Config, notes: &Notes, key: &str) {
    let file = notes.file_for_key(key);

    if !file.exists() {
        let _ = fs::write(&file, "");
    }

    let editor = std::env::var("EDITOR").unwrap_or_else(|_| "vim".to_string());
    let status = std::process::Command::new(&editor)
        .arg(&file)
        .status();

    if let Err(e) = status {
        if e.kind() == std::io::ErrorKind::NotFound {
            eprintln!("tnote: editor '{}' not found — run 'tnote setup' to configure", editor);
        } else {
            eprintln!("tnote: failed to run {}: {}", editor, e);
        }
        std::process::exit(1);
    }
}

fn cmd_name(notes: &Notes, name: Option<&str>) {
    let Some(name) = name else {
        if tmux::is_in_tmux() {
            tmux::prompt_name();
        } else {
            eprintln!("tnote name: provide a name, e.g.: tnote name <name>");
            std::process::exit(1);
        }
        return;
    };

    let (key, _) = current_note(notes);

    match notes.name_window(&key, name) {
        Ok(migrated) => {
            if migrated {
                println!("tnote name: migrated existing notes → {}", name);
            }
            if tmux::is_in_tmux() {
                tmux::rename_window(name);
                tmux::display_message(&format!("tnote: note named '{}'", name));
            }
            println!("tnote name: window note named '{}'", name);
        }
        Err(e) => {
            eprintln!("tnote name: error naming note: {}", e);
            std::process::exit(1);
        }
    }
}

fn cmd_show(notes: &Notes) {
    // Resolve: named (via .link) → tmux → shell, show first non-empty.
    let mut candidates: Vec<String> = Vec::new();
    if tmux::is_in_tmux() {
        if let Some(k) = tmux::window_key() {
            candidates.push(k);
        }
    }
    candidates.push(notes::shell_session_key());

    // Expand any key that has a .link into the named key first.
    let resolved: Vec<(String, String, PathBuf)> = candidates.into_iter().map(|k| {
        let label = notes.label_for_key(&k);
        let file  = notes.file_for_key(&k);
        (k, label, file)
    }).collect();

    for (_, label, file) in &resolved {
        let non_empty = file.exists() && file.metadata().map(|m| m.len() > 0).unwrap_or(false);
        if non_empty {
            println!("{}", format!("── tnote: {} ──", label).if_supports_color(Stdout, |t| t.style(Style::new().cyan().bold())));
            match fs::read_to_string(file) {
                Ok(content) => print!("{}", content),
                Err(e) => eprintln!("tnote show: {}", e.if_supports_color(Stderr, |t| t.red())),
            }
            println!("{}", "──────────────────────".if_supports_color(Stdout, |t| t.style(Style::new().cyan().bold())));
            return;
        }
    }

    let label = resolved.first().map(|(_, l, _)| l.as_str()).unwrap_or("unknown");
    println!("tnote show: (empty) [{}]", label.if_supports_color(Stdout, |t| t.dimmed()));
}

fn cmd_clean(notes: &Notes, scope: Option<ClearScope>, named: Option<&str>, dry_run: bool) {
    let mut any = false;

    if let Some(name) = named {
        match notes.remove_named(name, dry_run) {
            Ok(true) => {
                let verb = if dry_run { "would remove" } else { "removed" };
                println!("tnote clean: {} named note '{}'", verb, name.if_supports_color(Stdout, |t| t.yellow()));
                any = true;
            }
            Ok(false) => {
                eprintln!("tnote clean: named note '{}' not found", name);
                std::process::exit(1);
            }
            Err(e) => {
                eprintln!("tnote clean: {}", e.if_supports_color(Stderr, |t| t.red()));
                std::process::exit(1);
            }
        }
    }

    let lib_scope: Option<notes::ClearScope> = scope.map(Into::into);
    match notes.cleanup_orphaned(lib_scope.as_ref(), dry_run) {
        Ok(removed) if !removed.is_empty() => {
            let verb = if dry_run { "would remove" } else { "removed" };
            for key in &removed {
                println!("tnote clean: {} note {}", verb, key.if_supports_color(Stdout, |t| t.yellow()));
            }
            any = true;
        }
        Ok(_) => {}
        Err(e) => {
            eprintln!("tnote clean: {}", e.if_supports_color(Stderr, |t| t.red()));
            std::process::exit(1);
        }
    }

    let sessions = tmux::cleanup_popup_sessions(&notes.dir, dry_run);
    for s in &sessions {
        let verb = if dry_run { "would kill" } else { "killed" };
        println!("tnote clean: {} popup session {}", verb, s.if_supports_color(Stdout, |t| t.yellow()));
        any = true;
    }

    if !any {
        println!("tnote clean: {}", "nothing to clean up".if_supports_color(Stdout, |t| t.green()));
    }
}

fn cmd_list(notes: &Notes) {
    let (_, current_file) = current_note(notes);
    match notes.list_notes() {
        Ok(list) => {
            if list.is_empty() {
                println!("tnote list: (no notes yet)");
                return;
            }

            struct Row {
                category:      String,
                plain_label:   String,
                colored_label: String,
                lines:         usize,
                marker:        String,
                sources:       Vec<String>,
            }

            // Build all rows up front so we can compute global alignment widths.
            let rows: Vec<Row> = list.iter().map(|(cat, display, note_sources, lines, path)| {
                let shown = if cat == "shell" {
                    display.trim_start_matches("shell-").to_string()
                } else {
                    display.clone()
                };
                let sources: Vec<String> = note_sources.iter().map(|k| {
                    if k.starts_with("tmux-") {
                        let label = tmux::window_display_label(k)
                            .unwrap_or_else(|| k.strip_prefix("tmux-").unwrap_or(k).to_string());
                        format!("tmux - {}", label)
                    } else {
                        format!("shell - {}", k.strip_prefix("shell-").unwrap_or(k))
                    }
                }).collect();
                let is_current = *path == current_file;
                let colored_name = if is_current {
                    format!("{}", shown.if_supports_color(Stdout, |t| t.style(Style::new().bold())))
                } else {
                    shown.clone()
                };
                let marker = if is_current {
                    format!(" {}", "◀".if_supports_color(Stdout, |t| t.style(Style::new().green().bold())))
                } else {
                    String::new()
                };
                Row {
                    category:      cat.clone(),
                    plain_label:   shown,
                    colored_label: colored_name,
                    lines:         *lines,
                    marker,
                    sources,
                }
            }).collect();

            let max_width   = rows.iter().map(|r| r.plain_label.len()).max().unwrap_or(0);
            let lines_width = rows.iter().map(|r| r.lines).max().unwrap_or(0).to_string().len();

            let categories = [
                ("named", "named"),
                ("tmux",  "tmux (session+window)"),
                ("shell", "shell (pid)"),
                ("other", "other"),
            ];
            for (cat_key, cat_label) in categories {
                let cat_rows: Vec<_> = rows.iter().filter(|r| r.category == cat_key).collect();
                if cat_rows.is_empty() { continue; }
                println!("{}", format!("{}:", cat_label).if_supports_color(Stdout, |t| t.style(Style::new().cyan().bold())));
                for row in cat_rows {
                    let padding = max_width - row.plain_label.len();
                    println!("  {}{}  {:>width$} lines{}",
                        row.colored_label,
                        " ".repeat(padding),
                        row.lines,
                        row.marker,
                        width = lines_width,
                    );
                    for source in &row.sources {
                        println!("    {} {}", "↳".if_supports_color(Stdout, |t| t.dimmed()), source.if_supports_color(Stdout, |t| t.dimmed()));
                    }
                }
            }
        }
        Err(e) => {
            eprintln!("tnote list: {}", e);
            std::process::exit(1);
        }
    }
}

fn cmd_path(notes: &Notes) {
    let (_, file) = current_note(notes);
    println!("{}", file.display());
}

fn cmd_setup(config: &Config) {
    println!("tnote setup\n");

    let editor = prompt_editor(&config.editor);
    let key    = prompt("Key (tmux: prefix+?, shell: Ctrl+?)", &config.key);
    let width  = prompt_u16("Popup width",  config.width);
    let height = prompt_u16("Popup height", config.height);

    let new_config = Config {
        dir:    config.dir.clone(),
        editor,
        key,
        width,
        height,
    };

    if let Err(e) = new_config.save() {
        eprintln!("tnote setup: failed to save config: {}", e);
        std::process::exit(1);
    }

    install::run(&new_config);
}

fn prompt_editor(current: &str) -> String {
    let candidates = ["nvim", "vim", "vi", "nano", "emacs", "hx", "micro", "kak", "helix"];
    let available: Vec<&str> = candidates.iter()
        .copied()
        .filter(|e| install::which(e))
        .collect();

    if available.is_empty() {
        return prompt("Editor", current);
    }

    println!("  Available editors:");
    for (i, e) in available.iter().enumerate() {
        let marker = if *e == current { " ◀" } else { "" };
        println!("    {}. {}{}", i + 1, e, marker);
    }
    println!("  Enter a number or type a path.");

    loop {
        print!("  {:<18} [{}]: ", "Editor", current);
        let _ = io::stdout().flush();
        let mut input = String::new();
        let _ = io::stdin().read_line(&mut input);
        let trimmed = input.trim();

        if trimmed.is_empty() {
            return current.to_string();
        }
        if let Ok(n) = trimmed.parse::<usize>() {
            if n >= 1 && n <= available.len() {
                return available[n - 1].to_string();
            }
            eprintln!("  please enter a number between 1 and {}", available.len());
            continue;
        }
        return trimmed.to_string();
    }
}

fn prompt(label: &str, default: &str) -> String {
    print!("  {:<18} [{}]: ", label, default);
    let _ = io::stdout().flush();
    let mut input = String::new();
    let _ = io::stdin().read_line(&mut input);
    let trimmed = input.trim();
    if trimmed.is_empty() { default.to_string() } else { trimmed.to_string() }
}

fn prompt_u16(label: &str, default: u16) -> u16 {
    loop {
        let s = prompt(label, &default.to_string());
        match s.parse() {
            Ok(v) => return v,
            Err(_) => eprintln!("  please enter a number"),
        }
    }
}

