    // ── cleanup_orphaned ──────────────────────────────────────────────────────

    /// Returns a PID that is guaranteed to not be running.
    fn dead_pid() -> u32 {
        // Try a few high PIDs; pick the first one ps says is gone.
        for pid in [9_999_997u32, 9_999_998, 9_999_999] {
            if !is_pid_alive(pid) {
                return pid;
            }
        }
        panic!("could not find a dead PID for test");
    }

