        fs::write(tmp.path().join(format!("{}.md", key)), "stale").unwrap();
        let removed = notes.cleanup_orphaned(None, false).unwrap();
        assert!(removed.contains(&key));
        assert!(!tmp.path().join(format!("{}.md", key)).exists());
    }

